import L from 'leaflet';
import React from 'react';
import { MapContainer, TileLayer, Marker, Tooltip } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import axios from 'axios';

// Simplified text marker
const TextMarker = ({ text }) => {
  return L.divIcon({
    className: 'custom-icon',
    html: `<div style="font-size: 20px;">${text}</div>`,
  });
};

// Bus Information Panel
const BusInfoPanel = ({ bus, onClose }) => {
  if (!bus) return null;
  return (
    <div
      style={{
        position: 'absolute',
        top: '10px',
        right: '10px',
        width: '250px',
        background: 'rgba(255, 255, 255, 0.9)',
        padding: '10px',
        borderRadius: '8px',
        zIndex: 1000,
      }}
    >
      <button
        onClick={onClose}
        style={{
          float: 'right',
          border: 'none',
          background: 'transparent',
          cursor: 'pointer',
          fontSize: '16px',
        }}
      >
        ✖
      </button>
      <h3>Bus Details</h3>
      <p>
        <b>Bus ID:</b> {bus.id}
      </p>
      <p>
        <b>Route:</b> {bus.route}
      </p>
      <p>
        <b>Status:</b> {bus.status}
      </p>
      <p>
        <b>Speed:</b> {bus.speed ? bus.speed.toFixed(1) : 'N/A'} mph
      </p>
    </div>
  );
};

// Anomaly Information Panel
const AnomalyPanel = ({ anomalies }) => {
  if (!anomalies || anomalies.length === 0) return null;
  return (
    <div
      style={{
        position: 'absolute',
        top: '10px',
        left: '10px',
        width: '300px',
        maxHeight: '300px',
        overflowY: 'auto',
        background: 'rgba(255, 255, 255, 0.9)',
        padding: '10px',
        borderRadius: '8px',
        zIndex: 1000,
      }}
    >
      <h3 style={{ marginTop: 0 }}>Anomaly Feed</h3>
      {anomalies
        .slice()
        .reverse()
        .map((anomaly, index) => (
          <div
            key={index}
            style={{
              borderBottom: '1px solid #eee',
              paddingBottom: '5px',
              marginBottom: '5px',
            }}
          >
            <p style={{ margin: 0 }}>
              <b>Type:</b> {anomaly.type}
            </p>
            <p style={{ margin: 0 }}>
              <b>Bus ID:</b> {anomaly.bus_id}
            </p>
            <p style={{ margin: 0 }}>
              <b>Details:</b> {anomaly.details}
            </p>
          </div>
        ))}
    </div>
  );
};

export default function BusMap() {
  const [buses, setBuses] = React.useState([]);
  const [counts, setCounts] = React.useState({
    running_count: 0,
    ghost_count: 0,
    anomaly_count: 0,
  });
  const [selectedBus, setSelectedBus] = React.useState(null);
  const [anomalies, setAnomalies] = React.useState([]);

  React.useEffect(() => {
    const fetchData = () => {
      // Fetch Bus Data
      axios
        .get('http://127.0.0.1:8000/buses')
        .then((res) => {
          if (res.data && Array.isArray(res.data.buses)) {
            const anomalyCount = res.data.buses.filter(b => b.has_anomaly).length;
            setBuses(res.data.buses);
            setCounts({
              running_count: res.data.running_count,
              ghost_count: res.data.ghost_count,
              anomaly_count: anomalyCount,
            });
          }
        })
        .catch((err) => console.error('Error fetching bus data:', err));

      // Fetch Anomaly Data
      axios
        .get('http://127.0.0.1:8000/anomalies')
        .then((res) => {
          if (res.data && Array.isArray(res.data.anomalies)) {
            setAnomalies(res.data.anomalies);
          }
        })
        .catch((err) => console.error('Error fetching anomaly data:', err));
    };

    fetchData();
    const interval = setInterval(fetchData, 30000); // Fetch data every 30 seconds
    return () => clearInterval(interval);
  }, []);

  // Helper function to determine the bus marker icon
  const getBusMarker = (bus) => {
    if (bus.status === 'Ghost') {
      return '🔴'; // Red for Ghost
    }
    if (bus.has_anomaly) {
      return '🟠'; // Orange for Anomaly
    }
    return '🟢'; // Green for Running
  };

  return (
    <div style={{ position: 'relative', height: '100vh' }}>
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: '100%', width: '100%' }}
      >
        <TileLayer
          url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> &copy; CARTO'
        />

        {Array.isArray(buses) &&
          buses.map((bus) => (
            <Marker
              key={bus.id}
              position={[bus.lat, bus.lon]}
              icon={TextMarker({ text: getBusMarker(bus) })}
              eventHandlers={{
                click: () => {
                  setSelectedBus(bus);
                },
              }}
            >
              <Tooltip>Bus ID: {bus.id}</Tooltip>
            </Marker>
          ))}
      </MapContainer>

      <AnomalyPanel anomalies={anomalies} />
      <BusInfoPanel bus={selectedBus} onClose={() => setSelectedBus(null)} />

      <div
        style={{
          position: 'absolute',
          bottom: '20px',
          left: '10px',
          zIndex: 1000,
          background: 'rgba(255, 255, 255, 0.9)',
          padding: '10px 15px',
          borderRadius: '8px',
          fontWeight: 'bold',
        }}
      >
        🟢 Running: {counts.running_count} 🔴 Ghost: {counts.ghost_count} 🟠 Anomaly: {counts.anomaly_count}
      </div>
    </div>
  );
}
